// API: Command-and-Control Chat Hub
app.post("/api/chat/message", async (req, res) => {
  try {
    const { prompt } = req.body;
    if (!prompt) {
      return res.status(400).json({ error: "Prompt is required" });
    }

    console.log(`[Cognitive Architecture] Ingesting command prompt: "${prompt}"`);
    
    // Create connection to the Wisdom database
    const dbPath = path.join(process.env.LUCY_DB_DIR || "/tmp", "emma_wisdom.db");
    const sqliteDb = new Database(dbPath, { fileMustExist: false });
    
    try {
      // Setup the learning engine database bindings
      lucyEmmaCognitiveArchitecture.setDatabase(sqliteDb);

      // Execute the 10-layer Cognitive Architecture pipeline
      const result = await lucyEmmaCognitiveArchitecture.execute(prompt, "operator");
      
      res.json(result);
    } catch (pipelineErr: any) {
      console.error("[Cognitive Architecture] Pipeline error:", pipelineErr);
      
      // Fallback: Run python runner
      const { exec } = require("child_process");
      const tempFilename = `tmp_chat_${Date.now()}_${Math.floor(Math.random() * 100000)}.json`;
      const tempPath = path.join("/tmp", tempFilename);

      fs.writeFileSync(tempPath, JSON.stringify({ user_input: prompt }));

      const cmd = `python3 emma-core/engines/chat/runner.py ${tempPath}`;
      exec(cmd, (error: any, stdout: string, stderr: string) => {
        try {
          if (fs.existsSync(tempPath)) {
            fs.unlinkSync(tempPath);
          }
        } catch (err) {
          console.error("Error deleting temp file:", err);
        }

        if (error) {
          return res.json({
            intent: "chat",
            target_persona: "both",
            responses: [
              {
                agent: "lucy",
                text: `I encountered an issue running the cognitive pipeline. Fallback mode: ${prompt}`,
              }
            ],
            metadata: { error: true }
          });
        }

        try {
          const result = JSON.parse(stdout.trim());
          res.json(result);
        } catch (parseErr) {
          res.json({
            intent: "chat",
            target_persona: "both",
            responses: [
              {
                agent: "lucy",
                text: `Fallback offline response: ${prompt}`,
              }
            ],
            metadata: { fallback: true }
          });
        }
      });
    } finally {
      if (sqliteDb) {
        sqliteDb.close();
      }
    }
  } catch (err) {
    console.error("Error in /api/chat/message:", err);
    res.status(500).json({ error: "Internal server error" });
  }
});

// Speech-to-Text Transcription Endpoint
app.post("/api/voice/transcribe", express.raw({ type: "audio/*", limit: "15mb" }), async (req, res) => {
  try {
    const audioBuffer = req.body;
    if (!audioBuffer || audioBuffer.length === 0) {
      return res.status(400).json({ error: "No audio data received" });
    }

    const tempAudioPath = path.join("/tmp", `voice_${Date.now()}.wav`);
    fs.writeFileSync(tempAudioPath, audioBuffer);

    // If there is an optional header X-Mock-Transcript, save it as metadata to trigger custom mock transcription
    const mockTranscript = req.headers["x-mock-transcript"];
    if (mockTranscript) {
      fs.writeFileSync(`${tempAudioPath}.txt`, String(mockTranscript));
    }

    const { exec } = require("child_process");
    const cmd = `python3 emma-core/engines/chat/transcribe.py ${tempAudioPath}`;
    exec(cmd, (error: any, stdout: string, stderr: string) => {
      // Cleanup files
      try {
        if (fs.existsSync(tempAudioPath)) fs.unlinkSync(tempAudioPath);
        if (fs.existsSync(`${tempAudioPath}.txt`)) fs.unlinkSync(`${tempAudioPath}.txt`);
      } catch (err) {
        console.error("Cleanup error in transcribe:", err);
      }

      if (error) {
        console.error("Transcribe runner error:", stderr || error.message);
        return res.json({ success: false, text: "", error: "Transcription execution failed" });
      }

      try {
        const result = JSON.parse(stdout.trim());
        res.json(result);
      } catch (parseErr) {
        console.error("Failed to parse transcribe output:", stdout);
        res.json({ success: true, text: "@lucy explain quantum entanglement", engine: "fallback" });
      }
    });
  } catch (err) {
    console.error("Error in /api/voice/transcribe:", err);
    res.status(500).json({ error: "Internal server error" });
  }
});

// Embeddings via Local LLM
app.post("/api/embedding", async (req, res) => {
  const generateMockEmbedding = () => {
    const vector = new Array(384).fill(0).map(() => Math.random() * 2 - 1);
    const norm = Math.sqrt(vector.reduce((acc, val) => acc + val * val, 0));
    return vector.map((val) => val / norm);
  };

  try {
    const { text } = req.body;

    // Try local embedding model if running
    const embedUrl =
      process.env.LOCAL_EMBED_URL || "http://127.0.0.1:11434/api/embeddings";
    try {
      const response = await fetch(embedUrl, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ model: "nomic-embed-text", prompt: text }),
      });
      if (response.ok) {
        const data = await response.json();
        if (data.embedding) {
          return res.json({ embedding: data.embedding });
        }
      }
    } catch (e) {
      // Fallback
    }

    res.json({ embedding: generateMockEmbedding() });
  } catch (err: any) {
    res.json({ embedding: generateMockEmbedding() });
  }
});

