// API: Read file content for the Studio
app.get("/api/mirror/read-file", (req, res) => {
  try {
    const filePath = req.query.path as string;
    if (!filePath) {
      return res.status(400).json({ error: "Missing path parameter." });
    }
    
    const cleanPath = filePath.replace(/\\/g, "/").trim();
    // Path validation: restrict to emma-core/ and src/ or package.json/server.ts
    const isSafe = (
      cleanPath.startsWith("emma-core/") || 
      cleanPath.startsWith("src/") || 
      cleanPath === "server.ts" || 
      cleanPath === "package.json"
    ) && !cleanPath.includes("..") && !cleanPath.includes("identity/");
    
    if (!isSafe) {
      return res.status(403).json({ error: "Access denied. Target path lies outside allowed boundaries." });
    }
    
    const fs = require("fs");
    const fullPath = path.join(process.cwd(), cleanPath);
    if (!fs.existsSync(fullPath)) {
      return res.status(404).json({ error: "File not found." });
    }
    
    const content = fs.readFileSync(fullPath, "utf-8");
    res.json({ success: true, path: cleanPath, content });
  } catch (error: any) {
    res.status(500).json({ error: error.message });
  }
});

