async function startServer() {
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: {
        middlewareMode: true,
        // Without this, Vite opens its OWN websocket listener on port 5173
        // for HMR, separate from the Express httpServer on PORT. If 5173 is
        // already bound (e.g. a previous crashed instance), Vite throws an
        // unhandled 'error' event and kills the whole process. Sharing the
        // existing httpServer means HMR rides the same port as everything
        // else, so there's only one port to manage.
        hmr: { server: httpServer },
      },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), "dist");
    app.use(express.static(distPath));
    app.get("*", (req, res) => {
      res.sendFile(path.join(distPath, "index.html"));
    });
  }

  listenWithFallback(PORT);
}

// Instead of crashing with a raw EADDRINUSE stack trace when a previous
// instance is still running, try the next few ports and tell the user
// clearly what happened and where it actually landed.
function listenWithFallback(port: number, attemptsLeft = 5) {
  httpServer.once("error", (err: NodeJS.ErrnoException) => {
    if (err.code === "EADDRINUSE") {
      if (attemptsLeft <= 0) {
        console.error(
          `[Server] Port ${port} and the next several ports are all in use. ` +
          `Another Lucy/Emma instance is likely still running - close it ` +
          `(Task Manager / 'taskkill /IM node.exe /F' on Windows) and try again.`
        );
        process.exit(1);
        return;
      }
      console.warn(`[Server] Port ${port} is already in use. Trying ${port + 1}...`);
      listenWithFallback(port + 1, attemptsLeft - 1);
    } else {
      console.error("[Server] Failed to start:", err);
      process.exit(1);
    }
  });

  httpServer.listen(port, "0.0.0.0", () => {
    console.log(`Server running on http://localhost:${port}`);
    if (port !== PORT) {
      console.log(
        `[Server] Note: default port ${PORT} was busy, so the app is running ` +
        `on ${port} instead. Update any client pointing at ${PORT}.`
      );
    }
  });
}

startServer();
